export const getIeltsFeedback = async (taskType, prompt, essay, imageBase64, apiKey) => {
    if (!apiKey) throw new Error("API key is missing.");
    const ai = new GoogleGenAI({ apiKey });
    try {
        const isTask1 = taskType === 'Task 1';
        const bandDescriptors = isTask1 ? IELTS_TASK_1_BAND_DESCRIPTORS : IELTS_TASK_2_BAND_DESCRIPTORS;
        const taskCompletionCriterion = isTask1 ? "Task Achievement" : "Task Response";
        const wordCount = essay.trim() ? essay.trim().split(/\s+/).length : 0;

        let exemplarsSection = "";
        if (isTask1) {
            const subset = getRandomExemplars(IELTS_TASK_1_EXEMPLARS, 3);
            exemplarsSection = `
**Band 9.0 Exemplars for Task 1 (Reference):**
Use these Band 9.0 examples to calibrate your scoring for structure and task achievement.
---
${subset}
---
`;
        } else {
            const subset = getRandomExemplars(IELTS_TASK_2_EXEMPLARS, 3);
            exemplarsSection = `
**Band 6.0 vs 7.0 Calibration (CRITICAL):**
Study these examples to distinguish between Band 6 and Band 7 performance.
${IELTS_TASK_2_BAND_6_7_EXEMPLARS}
---
**High-Scoring Exemplars for Task 2 (Reference):**
Use these high-scoring examples to calibrate your evaluation.
---
${subset}
---
`;
        }

        const systemInstruction = `You are an expert IELTS examiner providing feedback on an IELTS Writing ${taskType} essay.

        **Examiner's Marking Method (Strict Adherence Required):**
        - **Process:** Start with ${taskCompletionCriterion}, then Coherence & Cohesion (CC), Lexical Resource (LR), and Grammatical Range (GRA).
        - **Matching:** For each criterion, find the band descriptor statement that best matches the essay features. Check positive features of that band and ensure no negative features from lower bands are present.

        **Academic Tone:**
        - Formal, objective, non-emotional. No slang/contractions.
        - Band 8-9: Natural, precise, clear. NOT overly ornate/fancy.

        **Band 8-9 Principles:**
        - **Slips:** Band 9 allows for "extremely rare" minor errors. Do NOT penalize slips that don't impede communication.
        - **Vocabulary:** Focus on precision and naturalness, NOT rarity.
        - **No Comparison:** Grade strictly against descriptors, not other essays.
        - **Justify:** YOU MUST QUOTE SPECIFIC DESCRIPTOR PHRASES to justify scores in 'strengths'/'weaknesses'.

        **Critical Scoring Rules:**
        1. **Word Count:** Task 1 target: 150. Task 2 target: 250. 
           - **Do NOT severely penalize** slight under-length if quality/development is high. Only penalize significant under-length that affects content.
        2. **Task 1:** Missing key features = Band 4 TA. No/unclear overview = Band 5 TA. No data = Band 5 TA.
        3. **Format:** Bullet points/lists = Band 4/5. Must be paragraphs.
        4. **Task 2 Evidence:** Fabricated statistics (e.g. "80% of people...") are a weakness. Reward real-world examples/experience.

        **Output Requirements:**
        1. Evaluate against Band 5-9 descriptors.
        2. **Consistency:** Scores for identical text must be identical.
        3. **Mistakes:** List specific LR/GRA errors. Suggested correction must differ from original.
        4. **Improvement:** Rewrite ALL awkward/unnatural sentences.

        **Evaluation Criteria:**
        ---
        ${bandDescriptors}
        ---
        ${exemplarsSection}
        `;

        const essayContent = `Please analyze the following essay based on the instructions.

        **Essay Prompt:** "${prompt}"
        **Word Count:** ${wordCount} words

        **Student's Essay:**
        ---
        ${essay}
        ---
        `;

        const parts = [];
        if (isTask1 && imageBase64) {
            parts.push({
                inlineData: { mimeType: 'image/jpeg', data: imageBase64 }
            });
        }
        parts.push({ text: essayContent });
        const contents = { parts };

        const baseFeedbackProperties = {
            strengths: { type: Type.STRING, description: "Positive feedback on the criterion, citing specific band descriptor phrases." },
            weaknesses: { type: Type.STRING, description: "Actionable areas for improvement on the criterion, citing specific band descriptor phrases." }
        };

        const mistakeSchema = {
            type: Type.OBJECT,
            properties: {
                originalPhrase: { type: Type.STRING, description: "The incorrect phrase from the essay." },
                suggestedCorrection: { type: Type.STRING, description: "The corrected version of the phrase." },
                explanation: { type: Type.STRING, description: "A brief explanation of the mistake." }
            },
            required: ['originalPhrase', 'suggestedCorrection', 'explanation']
        };

        const apiCall = async () => {
            const response = await ai.models.generateContent({
                model: feedbackModel,
                contents,
                config: {
                    systemInstruction,
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            taskCompletion: { 
                                type: Type.OBJECT,
                                properties: baseFeedbackProperties,
                                required: ['strengths', 'weaknesses']
                            },
                            taskCompletionScore: { type: Type.INTEGER, description: `An integer band score from 5-9 for ${taskCompletionCriterion}.` },
                            coherenceCohesion: {
                                type: Type.OBJECT,
                                properties: {
                                    ...baseFeedbackProperties,
                                    referencingAndSubstitution: { type: Type.STRING, description: "Specific feedback on referencing and substitution." }
                                },
                                required: ['strengths', 'weaknesses', 'referencingAndSubstitution']
                            },
                            coherenceCohesionScore: { type: Type.INTEGER, description: "An integer band score from 5-9 for Coherence & Cohesion." },
                            lexicalResource: {
                                type: Type.OBJECT,
                                properties: {
                                    ...baseFeedbackProperties,
                                    mistakes: {
                                        type: Type.ARRAY,
                                        description: "List of specific lexical mistakes and corrections. Returns empty array if none.",
                                        items: mistakeSchema
                                    }
                                },
                                required: ['strengths', 'weaknesses', 'mistakes']
                            },
                            lexicalResourceScore: { type: Type.INTEGER, description: "An integer band score from 5-9 for Lexical Resource." },
                            grammaticalRange: {
                                type: Type.OBJECT,
                                properties: {
                                    ...baseFeedbackProperties,
                                    mistakes: {
                                        type: Type.ARRAY,
                                        description: "List of specific grammatical mistakes and corrections. Returns empty array if none.",
                                        items: mistakeSchema
                                    }
                                },
                                required: ['strengths', 'weaknesses', 'mistakes']
                            },
                            grammaticalRangeScore: { type: Type.INTEGER, description: "An integer band score from 5-9 for Grammatical Range & Accuracy." },
                            sentenceImprovements: {
                                type: Type.ARRAY,
                                description: "A list of suggestions for ALL sentences that are awkward or unnatural.",
                                items: {
                                    type: Type.OBJECT,
                                        properties: {
                                        originalSentence: { type: Type.STRING, description: "The original sentence from the user's essay." },
                                        suggestedSentence: { type: Type.STRING, description: "The rewritten, more natural-sounding sentence." }
                                    },
                                    required: ['originalSentence', 'suggestedSentence']
                                }
                            }
                        },
                        required: ['taskCompletion', 'taskCompletionScore', 'coherenceCohesion', 'coherenceCohesionScore', 'lexicalResource', 'lexicalResourceScore', 'grammaticalRange', 'grammaticalRangeScore', 'sentenceImprovements']
                    },
                },
            });

            const jsonText = response.text;
            return JSON.parse(jsonText);
        };

        return await callWithRetry(apiCall);

    } catch (error) {
        handleApiError(error, 'get feedback from the AI');
    }
};

import React, { useState, useEffect, useCallback } from 'react';
import type { Feedback, TaskType, TaskContext, HighScore } from './types';
import { IELTS_TASK_2_PROMPTS } from './constants';
import { generateGuidance, getIeltsFeedback, generateBrainstormingIdeas } from './api/gemini.js';
import Header from './components/Header';
import PromptSection from './components/PromptSection';
import WritingEditor from './components/WritingEditor';
import FeedbackDisplay from './components/FeedbackDisplay';
import Dashboard from './components/Dashboard';

const getInitialTaskContext = (isLoadingPrompt = false, isInitialized = false): TaskContext => ({
  prompt: '',
  customPromptInput: '',
  isCustomPromptMode: false,
  guidancePoints: [],
  task1Guidance: null,
  brainstormingIdeas: [],
  task1Image: null,
  userEssay: '',
  feedback: null,
  isLoadingPrompt,
  isLoadingIdeas: false,
  isLoadingFeedback: false,
  isInitialized,
});

const calculateScoreNumeric = (feedback: Feedback): number => {
    const scores = [
        feedback.taskCompletionScore,
        feedback.coherenceCohesionScore,
        feedback.lexicalResourceScore,
        feedback.grammaticalRangeScore,
    ];
    const average = scores.reduce((a, b) => a + b, 0) / 4;
    return average;
};

const formatScore = (average: number): string => {
    const decimalPart = average - Math.floor(average);
    if (decimalPart >= 0.75) {
        return `${Math.ceil(average)}.0`;
    }
    if (decimalPart >= 0.25) {
        return `${Math.floor(average)}.5`;
    }
    return `${Math.floor(average)}.0`;
};

const App: React.FC = () => {
  const [taskType, setTaskType] = useState<TaskType>('Task 2');
  const [task1Context, setTask1Context] = useState<TaskContext>({
    ...getInitialTaskContext(false, true),
    isCustomPromptMode: true,
  });
  const [task2Context, setTask2Context] = useState<TaskContext>(getInitialTaskContext(true, false));
  const [error, setError] = useState<string | null>(null);

  // App Mode (Dashboard vs Main)
  const [isAppStarted, setIsAppStarted] = useState(false);

  // Score History
  const [history, setHistory] = useState<HighScore[]>([]);

  // API Key State
  const [apiKey, setApiKey] = useState<string | null>(null);
  const [apiKeyError, setApiKeyError] = useState<string | null>(null);

  // Global timer state
  const [timeRemaining, setTimeRemaining] = useState(3600); // 60 minutes
  const [isTimerActive, setIsTimerActive] = useState(false);

  const activeContext = taskType === 'Task 1' ? task1Context : task2Context;
  const setActiveContext = taskType === 'Task 1' ? setTask1Context : setTask2Context;

  useEffect(() => {
    const storedKey = localStorage.getItem('gemini-api-key');
    if (storedKey) {
      setApiKey(storedKey);
    }

    const storedHistory = localStorage.getItem('ielts-score-history');
    if (storedHistory) {
        try {
            setHistory(JSON.parse(storedHistory));
        } catch (e) {
            console.error("Failed to parse history", e);
        }
    }
  }, []);

  const saveHistory = (newRecord: HighScore) => {
    setHistory(prev => {
        const updated = [newRecord, ...prev]; // Newest first
        localStorage.setItem('ielts-score-history', JSON.stringify(updated));
        return updated;
    });
  };

  const handleApiError = (e: unknown) => {
    const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred.';
    // Update regex to include quota and 429 errors so the user can reset their key
    const isApiKeyError = /API key not valid|permission denied|API key is missing|quota|429/i.test(errorMessage);

    if (isApiKeyError) {
      localStorage.removeItem('gemini-api-key');
      setApiKey(null);
      setApiKeyError("Your API key has issues (Invalid or Quota Exceeded). Please provide a new one.");
    } else {
      setError(errorMessage);
    }
  };

  const handleNewPrompt = useCallback(async () => {
    if (!apiKey) {
      setApiKeyError("Please save a valid API key to generate a new prompt.");
      return;
    }
    setTask2Context(getInitialTaskContext(true, true));
    setError(null);
    setApiKeyError(null);

    try {
      const prompts = IELTS_TASK_2_PROMPTS;
      const newPrompt = prompts[Math.floor(Math.random() * prompts.length)];
      const guidanceResult = await generateGuidance('Task 2', newPrompt, null, apiKey);

      setTask2Context(prev => ({
        ...prev,
        prompt: newPrompt,
        guidancePoints: guidanceResult,
        isLoadingPrompt: false,
      }));

    } catch (e) {
      handleApiError(e);
      setTask2Context(prev => ({ ...prev, isLoadingPrompt: false }));
    }
  }, [apiKey]);

  const handleTaskTypeChange = (newType: TaskType) => {
    if (newType === taskType) return;
    setTaskType(newType);
  };

  // Initial prompt generation when entering the app
  useEffect(() => {
    if (isAppStarted && taskType === 'Task 2' && !task2Context.isInitialized && apiKey) {
      handleNewPrompt();
    }
  }, [isAppStarted, taskType, task2Context.isInitialized, handleNewPrompt, apiKey]);

  useEffect(() => {
    if (!isTimerActive) return;

    const intervalId = setInterval(() => {
      setTimeRemaining(prev => {
        if (prev <= 1) {
          setIsTimerActive(false);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(intervalId);
  }, [isTimerActive]);


  const handleSetCustomPromptMode = () => {
    setActiveContext(getInitialTaskContext(false, true));
    setError(null);
    setActiveContext(prev => ({...prev, isCustomPromptMode: true}));
  };

  const handleGenerateFromCustomPrompt = async () => {
    if (!apiKey) {
      setApiKeyError("Please save a valid API key to generate guidance.");
      return;
    }
    if (!activeContext.customPromptInput.trim()) {
      setError("Please enter a prompt.");
      return;
    }
    setError(null);
    setApiKeyError(null);
    setActiveContext(prev => ({ ...prev, isLoadingPrompt: true, guidancePoints: [], task1Guidance: null, brainstormingIdeas: [] }));

    try {
      const guidanceResult = await generateGuidance(taskType, activeContext.customPromptInput, activeContext.task1Image, apiKey);
      if (taskType === 'Task 1') {
        setActiveContext(prev => ({ 
          ...prev, 
          prompt: prev.customPromptInput, 
          task1Guidance: guidanceResult,
          isLoadingPrompt: false
        }));
      } else {
         setActiveContext(prev => ({ 
          ...prev, 
          prompt: prev.customPromptInput, 
          guidancePoints: guidanceResult,
          isLoadingPrompt: false
        }));
      }
    } catch (e) {
      handleApiError(e);
      setActiveContext(prev => ({ ...prev, isLoadingPrompt: false }));
    }
  };

  const handleGenerateIdeas = async () => {
    if (!apiKey) {
      setApiKeyError("Please save a valid API key to generate ideas.");
      return;
    }
    if (activeContext.guidancePoints.length === 0 || taskType === 'Task 1') return;
    setError(null);
    setApiKeyError(null);
    setActiveContext(prev => ({ ...prev, isLoadingIdeas: true, brainstormingIdeas: [] }));

    try {
      const ideas = await generateBrainstormingIdeas(activeContext.prompt, activeContext.guidancePoints, apiKey);
      setActiveContext(prev => ({ ...prev, brainstormingIdeas: ideas, isLoadingIdeas: false }));
    } catch (e) {
      handleApiError(e);
      setActiveContext(prev => ({ ...prev, isLoadingIdeas: false }));
    }
  };

  const handleSubmitEssay = async () => {
    if (!apiKey) {
      setApiKeyError("Please save a valid API key to get feedback.");
      return;
    }
    if (!activeContext.userEssay.trim()) {
      setError("Please write an essay before requesting feedback.");
      return;
    }
    setError(null);
    setApiKeyError(null);
    setActiveContext(prev => ({ ...prev, isLoadingFeedback: true, feedback: null }));

    try {
      const result = await getIeltsFeedback(taskType, activeContext.prompt, activeContext.userEssay, activeContext.task1Image, apiKey);

      const numericScore = calculateScoreNumeric(result);
      const displayScore = formatScore(numericScore);

      const newRecord: HighScore = {
          id: Date.now().toString(),
          nickname: 'User',
          date: new Date().toISOString(),
          score: numericScore,
          displayScore: displayScore,
          prompt: activeContext.prompt,
          essay: activeContext.userEssay,
          taskType: taskType
      };

      saveHistory(newRecord);

      setActiveContext(prev => ({ ...prev, feedback: result, isLoadingFeedback: false }));
    } catch (e) {
      handleApiError(e);
      setActiveContext(prev => ({ ...prev, isLoadingFeedback: false }));
    }
  };

  const handleSaveApiKey = (key: string) => {
    if (!key.startsWith('AIza')) {
        setApiKeyError("This doesn't look like a valid Gemini API key. Please check it.");
        return;
    }
    setApiKey(key);
    localStorage.setItem('gemini-api-key', key);
    setApiKeyError(null);
  };

  const handleToggleTimer = () => {
    if (timeRemaining <= 0) return;
    setIsTimerActive(prev => !prev);
  };

  const handleResetTimer = () => {
      setTimeRemaining(3600);
      setIsTimerActive(false);
  };

  const handleStartPractice = () => {
      setIsAppStarted(true);
  };

  const handleExportToWord = () => {
    const feedback = activeContext.feedback;
    const essay = activeContext.userEssay;
    const prompt = activeContext.prompt;

    if (!feedback) return;

    const overallScore = formatScore(calculateScoreNumeric(feedback));

    // Create HTML content for the Word document
    const htmlContent = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
            <meta charset="utf-8">
            <title>IELTS Writing Feedback</title>
            <style>
                body { font-family: 'Times New Roman', serif; font-size: 12pt; line-height: 1.5; }
                h1 { font-size: 18pt; font-weight: bold; text-align: center; margin-bottom: 20px; }
                h2 { font-size: 14pt; font-weight: bold; margin-top: 15px; margin-bottom: 10px; color: #2c3e50; }
                .essay-section { margin-bottom: 20px; border-bottom: 1px solid #ddd; padding-bottom: 20px; }
                .score-box { font-size: 16pt; font-weight: bold; color: #e74c3c; margin-bottom: 20px; text-align: center; }
                table { width: 100%; border-collapse: collapse; margin-top: 20px; }
                th, td { border: 1px solid #000; padding: 10px; vertical-align: top; }
                th { background-color: #f2f2f2; font-weight: bold; }
                .criteria-name { font-weight: bold; color: #2980b9; }
                .score-cell { font-weight: bold; text-align: center; }
            </style>
        </head>
        <body>
            <h1>IELTS Writing Feedback Report</h1>

            <div class="score-box">
                Overall Band Score: ${overallScore}
            </div>

            <div class="essay-section">
                <h2>Prompt</h2>
                <p><i>${prompt}</i></p>

                <h2>Your Essay</h2>
                <p>${essay.replace(/\n/g, '<br>')}</p>
            </div>

            <h2>Detailed Evaluation</h2>
            <table>
                <thead>
                    <tr>
                        <th style="width: 20%">Criteria</th>
                        <th style="width: 10%">Score</th>
                        <th style="width: 35%">Strengths</th>
                        <th style="width: 35%">Weaknesses</th>
                    </tr>
                </thead>
                <tbody>
                    <tr>
                        <td class="criteria-name">${taskType === 'Task 1' ? 'Task Achievement' : 'Task Response'}</td>
                        <td class="score-cell">${feedback.taskCompletionScore}</td>
                        <td>${feedback.taskCompletion.strengths}</td>
                        <td>${feedback.taskCompletion.weaknesses}</td>
                    </tr>
                    <tr>
                        <td class="criteria-name">Coherence & Cohesion</td>
                        <td class="score-cell">${feedback.coherenceCohesionScore}</td>
                        <td>${feedback.coherenceCohesion.strengths}</td>
                        <td>${feedback.coherenceCohesion.weaknesses}</td>
                    </tr>
                    <tr>
                        <td class="criteria-name">Lexical Resource</td>
                        <td class="score-cell">${feedback.lexicalResourceScore}</td>
                        <td>${feedback.lexicalResource.strengths}</td>
                        <td>
                            ${feedback.lexicalResource.weaknesses}
                            ${feedback.lexicalResource.mistakes && feedback.lexicalResource.mistakes.length > 0 ? 
                                '<br><b>Mistakes:</b><br>' + feedback.lexicalResource.mistakes.map(m => `"${m.originalPhrase}" -> "${m.suggestedCorrection}"`).join('<br>') 
                                : ''}
                        </td>
                    </tr>
                    <tr>
                        <td class="criteria-name">Grammatical Range & Accuracy</td>
                        <td class="score-cell">${feedback.grammaticalRangeScore}</td>
                        <td>${feedback.grammaticalRange.strengths}</td>
                        <td>
                            ${feedback.grammaticalRange.weaknesses}
                             ${feedback.grammaticalRange.mistakes && feedback.grammaticalRange.mistakes.length > 0 ? 
                                '<br><b>Mistakes:</b><br>' + feedback.grammaticalRange.mistakes.map(m => `"${m.originalPhrase}" -> "${m.suggestedCorrection}"`).join('<br>') 
                                : ''}
                        </td>
                    </tr>
                </tbody>
            </table>
            <br>
            <p><i>Generated by IELTS Writing Master AI</i></p>
        </body>
        </html>
    `;

    // Create a Blob and trigger download
    const blob = new Blob(['\ufeff', htmlContent], {
        type: 'application/msword'
    });

    // Create link and simulate click
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `IELTS_Feedback_${new Date().toISOString().slice(0,10)}.doc`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const isLoading = activeContext.isLoadingPrompt || activeContext.isLoadingFeedback;

  if (!isAppStarted) {
      return (
          <Dashboard 
            history={history}
            apiKey={apiKey}
            onSaveApiKey={handleSaveApiKey}
            onStartPractice={handleStartPractice}
            apiKeyError={apiKeyError}
          />
      );
  }

  return (
    <div className="min-h-screen flex flex-col">
      <Header 
        taskType={taskType} 
        setTaskType={handleTaskTypeChange}
        isLoading={isLoading}
        timeRemaining={timeRemaining}
        isTimerActive={isTimerActive}
        onToggleTimer={handleToggleTimer}
        onResetTimer={handleResetTimer}
        apiKey={apiKey}
        onSaveApiKey={handleSaveApiKey}
        apiKeyError={apiKeyError}
      />
      <main className="flex-grow container mx-auto p-4 md:p-6 lg:p-8 max-w-7xl">
        <div className="flex flex-col gap-8">
            <div className="flex justify-between items-center">
                <button 
                    onClick={() => setIsAppStarted(false)}
                    className="self-start text-sm text-sky-600 hover:text-sky-800 flex items-center gap-1 font-medium"
                >
                    &larr; Back to Dashboard
                </button>
            </div>

          {/* Prompt and Editor Section */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
            <div className="h-full">
                <PromptSection
                  taskType={taskType}
                  prompt={activeContext.prompt}
                  guidancePoints={activeContext.guidancePoints}
                  task1Guidance={activeContext.task1Guidance}
                  ideas={activeContext.brainstormingIdeas}
                  onNewPrompt={handleNewPrompt}
                  isLoadingPrompt={activeContext.isLoadingPrompt}
                  isLoadingIdeas={activeContext.isLoadingIdeas}
                  onGenerateIdeas={handleGenerateIdeas}
                  isCustomPromptMode={activeContext.isCustomPromptMode}
                  onSetCustomPromptMode={handleSetCustomPromptMode}
                  customPromptInput={activeContext.customPromptInput}
                  setCustomPromptInput={(val) => setActiveContext(p => ({...p, customPromptInput: val}))}
                  onGenerateFromCustomPrompt={handleGenerateFromCustomPrompt}
                  task1Image={activeContext.task1Image}
                  setTask1Image={(val) => setActiveContext(p => ({...p, task1Image: val}))}
                  apiKey={apiKey}
                />
            </div>
            <div className="h-full">
                <WritingEditor
                  taskType={taskType}
                  essay={activeContext.userEssay}
                  setEssay={(val) => setActiveContext(p => ({...p, userEssay: val}))}
                  onSubmit={handleSubmitEssay}
                  isLoading={activeContext.isLoadingFeedback}
                  onExportWord={handleExportToWord}
                  hasFeedback={!!activeContext.feedback}
                />
            </div>
          </div>

          {/* Feedback Section */}
          <div className="w-full">
             <FeedbackDisplay 
                taskType={taskType} 
                feedback={activeContext.feedback} 
                isLoading={activeContext.isLoadingFeedback} 
            />
          </div>
        </div>
        {error && (
            <div className="fixed bottom-5 right-5 bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded-lg shadow-lg z-50" role="alert">
                <strong className="font-bold">Error: </strong>
                <span className="block sm:inline">{error}</span>
                <span className="absolute top-0 bottom-0 right-0 px-4 py-3" onClick={() => setError(null)}>
                    <svg className="fill-current h-6 w-6 text-red-500" role="button" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><title>Close</title><path d="M14.348 14.849a1.2 1.2 0 0 1-1.697 0L10 11.819l-2.651 3.029a1.2 1.2 0 1 1-1.697-1.697l2.758-3.15-2.759-3.152a1.2 1.2 0 1 1 1.697-1.697L10 8.183l2.651-3.031a1.2 1.2 0 1 1 1.697 1.697l-2.758 3.152 2.758 3.15a1.2 1.2 0 0 1 0 1.698z"/></svg>
                </span>
            </div>
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import type { TaskType, Feedback, MistakeCorrection } from '../types';
import { SparklesIcon, EyeIcon, PencilIcon } from './icons';
import { LoadingSpinner } from './LoadingSpinner';

interface WritingEditorProps {
  taskType: TaskType;
  essay: string;
  setEssay: (value: string) => void;
  onSubmit: () => void;
  isLoading: boolean;
  onExportWord?: () => void;
  feedback: Feedback | null;
}

const DocumentIcon: React.FC<{ className?: string }> = (props) => (
  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" {...props}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M19.5 14.25v-2.625a3.375 3.375 0 00-3.375-3.375h-1.5A1.125 1.125 0 0113.5 7.125v-1.5a3.375 3.375 0 00-3.375-3.375H8.25m2.25 0H5.625c-.621 0-1.125.504-1.125 1.125v17.25c0 .621.504 1.125 1.125 1.125h12.75c.621 0 1.125-.504 1.125-1.125V11.25a9 9 0 00-9-9z" />
  </svg>
);

// Helper to escape regex characters
function escapeRegExp(string: string) {
  return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); 
}

const WritingEditor: React.FC<WritingEditorProps> = ({ 
    taskType, 
    essay, 
    setEssay, 
    onSubmit, 
    isLoading, 
    onExportWord, 
    feedback 
}) => {
  const [viewMode, setViewMode] = useState<'write' | 'review'>('write');

  // Automatically switch to review mode when feedback arrives
  useEffect(() => {
    if (feedback) {
        setViewMode('review');
    } else {
        setViewMode('write');
    }
  }, [feedback]);

  const wordCount = essay.trim() ? essay.trim().split(/\s+/).length : 0;
  const wordTarget = taskType === 'Task 1' ? 150 : 250;

  // Process the essay text to inject highlights
  const highlightedContent = useMemo(() => {
    if (!feedback) return essay;

    let processedHtml = essay
        .replace(/&/g, "&amp;")
        .replace(/</g, "&lt;")
        .replace(/>/g, "&gt;")
        .replace(/\n/g, "<br/>");

    // Gather all mistakes
    const allMistakes: MistakeCorrection[] = [
        ...(feedback.lexicalResource.mistakes || []),
        ...(feedback.grammaticalRange.mistakes || [])
    ];

    // Sort by length (longest first) to prevent replacing substrings of other mistakes
    allMistakes.sort((a, b) => b.originalPhrase.length - a.originalPhrase.length);

    // Naive replacement strategy - iterates through mistakes and wraps occurrences
    // Note: This matches the first occurrence found repeatedly. 
    // Ideally, the backend would return indices, but we are working with string matching here.
    allMistakes.forEach(mistake => {
        const cleanPhrase = escapeRegExp(mistake.originalPhrase.trim());
        if (!cleanPhrase) return;

        // Create a regex that looks for the phrase, ensuring we don't replace inside existing HTML tags
        // This is a simplified regex approach.
        const regex = new RegExp(`(${cleanPhrase})(?![^<]*>|[^<>]*<\/span>)`, 'gi');

        processedHtml = processedHtml.replace(regex, (match) => {
            return `
            <span class="group relative cursor-pointer mx-0.5 border-b-2 border-rose-400 bg-rose-50 hover:bg-rose-100 transition-colors">
                ${match}
                <span class="absolute bottom-full left-1/2 -translate-x-1/2 w-64 bg-slate-800 text-white text-xs p-3 rounded-lg shadow-xl hidden group-hover:block z-20 mb-2 pointer-events-none">
                    <span class="block font-bold text-green-300 text-sm mb-1">
                       Correction: ${mistake.suggestedCorrection}
                    </span>
                    <span class="block text-slate-300 leading-snug">
                       ${mistake.explanation}
                    </span>
                    <svg class="absolute text-slate-800 h-2 w-full left-0 top-full" x="0px" y="0px" viewBox="0 0 255 255" xml:space="preserve"><polygon class="fill-current" points="0,0 127.5,127.5 255,0"/></svg>
                </span>
            </span>
            `;
        });
    });

    return processedHtml;
  }, [essay, feedback]);

  return (
    <div className="bg-white p-6 rounded-lg shadow-sm border border-slate-200 h-full flex flex-col">
      <div className="flex justify-between items-center mb-4">
        <h2 className="text-lg font-semibold text-slate-700">Your Essay</h2>

        {/* View Mode Toggles */}
        {feedback && (
            <div className="flex bg-slate-100 rounded-lg p-1">
                <button
                    onClick={() => setViewMode('write')}
                    className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-colors ${
                        viewMode === 'write' ? 'bg-white text-slate-800 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                    }`}
                >
                    <PencilIcon className="h-4 w-4" />
                    Edit
                </button>
                <button
                    onClick={() => setViewMode('review')}
                    className={`flex items-center gap-2 px-3 py-1.5 text-sm font-medium rounded-md transition-colors ${
                        viewMode === 'review' ? 'bg-white text-rose-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                    }`}
                >
                    <EyeIcon className="h-4 w-4" />
                    Review Mistakes
                </button>
            </div>
        )}
      </div>

      <div className="relative flex-grow min-h-[500px]">
        {viewMode === 'write' ? (
            <textarea
                value={essay}
                onChange={(e) => setEssay(e.target.value)}
                placeholder={`Start writing your response here... (Aim for at least ${wordTarget} words)`}
                className="w-full h-full p-4 border border-slate-300 rounded-md resize-none focus:ring-2 focus:ring-sky-500 focus:border-sky-500 transition-shadow duration-200 font-sans text-base leading-relaxed"
                disabled={isLoading}
            />
        ) : (
            <div 
                className="w-full h-full p-4 border border-slate-300 rounded-md overflow-y-auto bg-white font-sans text-base leading-relaxed whitespace-pre-wrap"
                dangerouslySetInnerHTML={{ __html: highlightedContent }}
            />
        )}

        <div className={`absolute bottom-3 right-3 text-sm font-medium px-2 py-1 rounded shadow-sm border ${wordCount >= wordTarget ? 'text-green-700 bg-green-50 border-green-200' : 'text-slate-500 bg-slate-50 border-slate-200'}`}>
          {wordCount} words
        </div>
      </div>

      <div className="mt-4 flex justify-end gap-3">
        {feedback && onExportWord && (
             <button
                onClick={onExportWord}
                className="flex items-center justify-center gap-2 px-4 py-3 text-base font-semibold text-indigo-700 bg-indigo-100 rounded-lg shadow-sm hover:bg-indigo-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-indigo-500 transition-all duration-200"
                title="Export feedback to Word"
            >
                <DocumentIcon className="h-5 w-5" />
                Export
            </button>
        )}
        <button
          onClick={onSubmit}
          disabled={isLoading || wordCount === 0}
          className="flex items-center justify-center gap-2 px-6 py-3 text-base font-semibold text-white bg-sky-600 rounded-lg shadow-md hover:bg-sky-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-sky-500 transition-all duration-200 disabled:bg-slate-400 disabled:cursor-not-allowed"
        >
          {isLoading ? (
            <>
              <LoadingSpinner className="h-5 w-5" />
              Analyzing...
            </>
          ) : (
            <>
              <SparklesIcon className="h-5 w-5" />
              {feedback ? 'Re-Evaluate' : 'Get Feedback'}
            </>
          )}
        </button>
      </div>
    </div>
  );
};

export default WritingEditor;

import React, { useState, useEffect, useCallback } from 'react';
import type { Feedback, TaskType, TaskContext, HighScore } from './types';
import { IELTS_TASK_2_PROMPTS } from './constants';
import { generateGuidance, getIeltsFeedback, generateBrainstormingIdeas } from './api/gemini.js';
import Header from './components/Header';
import PromptSection from './components/PromptSection';
import WritingEditor from './components/WritingEditor';
import FeedbackDisplay from './components/FeedbackDisplay';
import Dashboard from './components/Dashboard';

const getInitialTaskContext = (isLoadingPrompt = false, isInitialized = false): TaskContext => ({
  prompt: '',
  customPromptInput: '',
  isCustomPromptMode: false,
  guidancePoints: [],
  task1Guidance: null,
  brainstormingIdeas: [],
  task1Image: null,
  userEssay: '',
  feedback: null,
  isLoadingPrompt,
  isLoadingIdeas: false,
  isLoadingFeedback: false,
  isInitialized,
});

const calculateScoreNumeric = (feedback: Feedback): number => {
    const scores = [
        feedback.taskCompletionScore,
        feedback.coherenceCohesionScore,
        feedback.lexicalResourceScore,
        feedback.grammaticalRangeScore,
    ];
    const average = scores.reduce((a, b) => a + b, 0) / 4;
    return average;
};

const formatScore = (average: number): string => {
    const decimalPart = average - Math.floor(average);
    if (decimalPart >= 0.75) {
        return `${Math.ceil(average)}.0`;
    }
    if (decimalPart >= 0.25) {
        return `${Math.floor(average)}.5`;
    }
    return `${Math.floor(average)}.0`;
};

const App: React.FC = () => {
  const [taskType, setTaskType] = useState<TaskType>('Task 2');
  const [task1Context, setTask1Context] = useState<TaskContext>({
    ...getInitialTaskContext(false, true),
    isCustomPromptMode: true,
  });
  const [task2Context, setTask2Context] = useState<TaskContext>(getInitialTaskContext(true, false));
  const [error, setError] = useState<string | null>(null);

  // App Mode (Dashboard vs Main)
  const [isAppStarted, setIsAppStarted] = useState(false);

  // Score History
  const [history, setHistory] = useState<HighScore[]>([]);

  // API Key State
  const [apiKey, setApiKey] = useState<string | null>(null);
  const [apiKeyError, setApiKeyError] = useState<string | null>(null);

  // Global timer state
  const [timeRemaining, setTimeRemaining] = useState(3600); // 60 minutes
  const [isTimerActive, setIsTimerActive] = useState(false);

  const activeContext = taskType === 'Task 1' ? task1Context : task2Context;
  const setActiveContext = taskType === 'Task 1' ? setTask1Context : setTask2Context;

  useEffect(() => {
    const storedKey = localStorage.getItem('gemini-api-key');
    if (storedKey) {
      setApiKey(storedKey);
    }

    const storedHistory = localStorage.getItem('ielts-score-history');
    if (storedHistory) {
        try {
            setHistory(JSON.parse(storedHistory));
        } catch (e) {
            console.error("Failed to parse history", e);
        }
    }
  }, []);

  const saveHistory = (newRecord: HighScore) => {
    setHistory(prev => {
        const updated = [newRecord, ...prev]; // Newest first
        localStorage.setItem('ielts-score-history', JSON.stringify(updated));
        return updated;
    });
  };

  const handleApiError = (e: unknown) => {
    const errorMessage = e instanceof Error ? e.message : 'An unknown error occurred.';
    // Update regex to include quota and 429 errors so the user can reset their key
    const isApiKeyError = /API key not valid|permission denied|API key is missing|quota|429/i.test(errorMessage);

    if (isApiKeyError) {
      localStorage.removeItem('gemini-api-key');
      setApiKey(null);
      setApiKeyError("Your API key has issues (Invalid or Quota Exceeded). Please provide a new one.");
    } else {
      setError(errorMessage);
    }
  };

  const handleNewPrompt = useCallback(async () => {
    if (!apiKey) {
      setApiKeyError("Please save a valid API key to generate a new prompt.");
      return;
    }
    setTask2Context(getInitialTaskContext(true, true));
    setError(null);
    setApiKeyError(null);

    try {
      const prompts = IELTS_TASK_2_PROMPTS;
      const newPrompt = prompts[Math.floor(Math.random() * prompts.length)];
      const guidanceResult = await generateGuidance('Task 2', newPrompt, null, apiKey);

      setTask2Context(prev => ({
        ...prev,
        prompt: newPrompt,
        guidancePoints: guidanceResult,
        isLoadingPrompt: false,
      }));

    } catch (e) {
      handleApiError(e);
      setTask2Context(prev => ({ ...prev, isLoadingPrompt: false }));
    }
  }, [apiKey]);

  const handleTaskTypeChange = (newType: TaskType) => {
    if (newType === taskType) return;
    setTaskType(newType);
  };

  // Initial prompt generation when entering the app
  useEffect(() => {
    if (isAppStarted && taskType === 'Task 2' && !task2Context.isInitialized && apiKey) {
      handleNewPrompt();
    }
  }, [isAppStarted, taskType, task2Context.isInitialized, handleNewPrompt, apiKey]);

  useEffect(() => {
    if (!isTimerActive) return;

    const intervalId = setInterval(() => {
      setTimeRemaining(prev => {
        if (prev <= 1) {
          setIsTimerActive(false);
          return 0;
        }
        return prev - 1;
      });
    }, 1000);

    return () => clearInterval(intervalId);
  }, [isTimerActive]);


  const handleSetCustomPromptMode = () => {
    setActiveContext(getInitialTaskContext(false, true));
    setError(null);
    setActiveContext(prev => ({...prev, isCustomPromptMode: true}));
  };

  const handleGenerateFromCustomPrompt = async () => {
    if (!apiKey) {
      setApiKeyError("Please save a valid API key to generate guidance.");
      return;
    }
    if (!activeContext.customPromptInput.trim()) {
      setError("Please enter a prompt.");
      return;
    }
    setError(null);
    setApiKeyError(null);
    setActiveContext(prev => ({ ...prev, isLoadingPrompt: true, guidancePoints: [], task1Guidance: null, brainstormingIdeas: [] }));

    try {
      const guidanceResult = await generateGuidance(taskType, activeContext.customPromptInput, activeContext.task1Image, apiKey);
      if (taskType === 'Task 1') {
        setActiveContext(prev => ({ 
          ...prev, 
          prompt: prev.customPromptInput, 
          task1Guidance: guidanceResult,
          isLoadingPrompt: false
        }));
      } else {
         setActiveContext(prev => ({ 
          ...prev, 
          prompt: prev.customPromptInput, 
          guidancePoints: guidanceResult,
          isLoadingPrompt: false
        }));
      }
    } catch (e) {
      handleApiError(e);
      setActiveContext(prev => ({ ...prev, isLoadingPrompt: false }));
    }
  };

  const handleGenerateIdeas = async () => {
    if (!apiKey) {
      setApiKeyError("Please save a valid API key to generate ideas.");
      return;
    }
    if (activeContext.guidancePoints.length === 0 || taskType === 'Task 1') return;
    setError(null);
    setApiKeyError(null);
    setActiveContext(prev => ({ ...prev, isLoadingIdeas: true, brainstormingIdeas: [] }));

    try {
      const ideas = await generateBrainstormingIdeas(activeContext.prompt, activeContext.guidancePoints, apiKey);
      setActiveContext(prev => ({ ...prev, brainstormingIdeas: ideas, isLoadingIdeas: false }));
    } catch (e) {
      handleApiError(e);
      setActiveContext(prev => ({ ...prev, isLoadingIdeas: false }));
    }
  };

  const handleSubmitEssay = async () => {
    if (!apiKey) {
      setApiKeyError("Please save a valid API key to get feedback.");
      return;
    }
    if (!activeContext.userEssay.trim()) {
      setError("Please write an essay before requesting feedback.");
      return;
    }
    setError(null);
    setApiKeyError(null);
    setActiveContext(prev => ({ ...prev, isLoadingFeedback: true, feedback: null }));

    try {
      const result = await getIeltsFeedback(taskType, activeContext.prompt, activeContext.userEssay, activeContext.task1Image, apiKey);

      const numericScore = calculateScoreNumeric(result);
      const displayScore = formatScore(numericScore);

      const newRecord: HighScore = {
          id: Date.now().toString(),
          nickname: 'User',
          date: new Date().toISOString(),
          score: numericScore,
          displayScore: displayScore,
          prompt: activeContext.prompt,
          essay: activeContext.userEssay,
          taskType: taskType
      };

      saveHistory(newRecord);

      setActiveContext(prev => ({ ...prev, feedback: result, isLoadingFeedback: false }));
    } catch (e) {
      handleApiError(e);
      setActiveContext(prev => ({ ...prev, isLoadingFeedback: false }));
    }
  };

  const handleSaveApiKey = (key: string) => {
    if (!key.startsWith('AIza')) {
        setApiKeyError("This doesn't look like a valid Gemini API key. Please check it.");
        return;
    }
    setApiKey(key);
    localStorage.setItem('gemini-api-key', key);
    setApiKeyError(null);
  };

  const handleToggleTimer = () => {
    if (timeRemaining <= 0) return;
    setIsTimerActive(prev => !prev);
  };

  const handleResetTimer = () => {
      setTimeRemaining(3600);
      setIsTimerActive(false);
  };

  const handleStartPractice = () => {
      setIsAppStarted(true);
  };

  const handleExportToWord = () => {
    const feedback = activeContext.feedback;
    const essay = activeContext.userEssay;
    const prompt = activeContext.prompt;

    if (!feedback) return;

    const overallScore = formatScore(calculateScoreNumeric(feedback));

    // Create HTML content for the Word document
    const htmlContent = `
        <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
        <head>
            <meta charset="utf-8">
            <title>IELTS Writing Feedback</title>
            <style>
                body { font-family: 'Times New Roman', serif; font-size: 12pt; line-height: 1.5; }
                h1 { font-size: 18pt; font-weight: bold; text-align: center; margin-bottom: 20px; }
                h2 { font-size: 14pt; font-weight: bold; margin-top: 15px; margin-bottom: 10px; color: #2c3e50; }
                .essay-section { margin-bottom: 20px; border-bottom: 1px solid #ddd; padding-bottom: 20px; }
                .score-box { font-size: 16pt; font-weight: bold; color: #e74c3c; margin-bottom: 20px; text-align: center; }
                table { width: 100%; border-collapse: collapse; margin-top: 20px; }
                th, td { border: 1px solid #000; padding: 10px; vertical-align: top; }
                th { background-color: #f2f2f2; font-weight: bold; }
                .criteria-name { font-weight: bold; color: #2980b9; }
                .score-cell { font-weight: bold; text-align: center; }
            </style>
        </head>
        <body>
            <h1>IELTS Writing Feedback Report</h1>

            <div class="score-box">
                Overall Band Score: ${overallScore}
            </div>

            <div class="essay-section">
                <h2>Prompt</h2>
                <p><i>${prompt}</i></p>

                <h2>Your Essay</h2>
                <p>${essay.replace(/\n/g, '<br>')}</p>
            </div>

            <h2>Detailed Evaluation</h2>
            <table>
                <thead>
                    <tr>
                        <th style="width: 20%">Criteria</th>
                        <th style="width: 10%">Score</th>
                        <th style="width: 35%">Strengths</th>
                        <th style="width: 35%">Weaknesses</th>
                    </tr>
                </thead>
                <tbody>
                    <tr>
                        <td class="criteria-name">${taskType === 'Task 1' ? 'Task Achievement' : 'Task Response'}</td>
                        <td class="score-cell">${feedback.taskCompletionScore}</td>
                        <td>${feedback.taskCompletion.strengths}</td>
                        <td>${feedback.taskCompletion.weaknesses}</td>
                    </tr>
                    <tr>
                        <td class="criteria-name">Coherence & Cohesion</td>
                        <td class="score-cell">${feedback.coherenceCohesionScore}</td>
                        <td>${feedback.coherenceCohesion.strengths}</td>
                        <td>${feedback.coherenceCohesion.weaknesses}</td>
                    </tr>
                    <tr>
                        <td class="criteria-name">Lexical Resource</td>
                        <td class="score-cell">${feedback.lexicalResourceScore}</td>
                        <td>${feedback.lexicalResource.strengths}</td>
                        <td>
                            ${feedback.lexicalResource.weaknesses}
                            ${feedback.lexicalResource.mistakes && feedback.lexicalResource.mistakes.length > 0 ? 
                                '<br><b>Mistakes:</b><br>' + feedback.lexicalResource.mistakes.map(m => `"${m.originalPhrase}" -> "${m.suggestedCorrection}"`).join('<br>') 
                                : ''}
                        </td>
                    </tr>
                    <tr>
                        <td class="criteria-name">Grammatical Range & Accuracy</td>
                        <td class="score-cell">${feedback.grammaticalRangeScore}</td>
                        <td>${feedback.grammaticalRange.strengths}</td>
                        <td>
                            ${feedback.grammaticalRange.weaknesses}
                             ${feedback.grammaticalRange.mistakes && feedback.grammaticalRange.mistakes.length > 0 ? 
                                '<br><b>Mistakes:</b><br>' + feedback.grammaticalRange.mistakes.map(m => `"${m.originalPhrase}" -> "${m.suggestedCorrection}"`).join('<br>') 
                                : ''}
                        </td>
                    </tr>
                </tbody>
            </table>
            <br>
            <p><i>Generated by IELTS Writing Master AI</i></p>
        </body>
        </html>
    `;

    // Create a Blob and trigger download
    const blob = new Blob(['\ufeff', htmlContent], {
        type: 'application/msword'
    });

    // Create link and simulate click
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `IELTS_Feedback_${new Date().toISOString().slice(0,10)}.doc`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const isLoading = activeContext.isLoadingPrompt || activeContext.isLoadingFeedback;

  if (!isAppStarted) {
      return (
          <Dashboard 
            history={history}
            apiKey={apiKey}
            onSaveApiKey={handleSaveApiKey}
            onStartPractice={handleStartPractice}
            apiKeyError={apiKeyError}
          />
      );
  }

  return (
    <div className="min-h-screen flex flex-col">
      <Header 
        taskType={taskType} 
        setTaskType={handleTaskTypeChange}
        isLoading={isLoading}
        timeRemaining={timeRemaining}
        isTimerActive={isTimerActive}
        onToggleTimer={handleToggleTimer}
        onResetTimer={handleResetTimer}
        apiKey={apiKey}
        onSaveApiKey={handleSaveApiKey}
        apiKeyError={apiKeyError}
      />
      <main className="flex-grow container mx-auto p-4 md:p-6 lg:p-8 max-w-7xl">
        <div className="flex flex-col gap-8">
            <div className="flex justify-between items-center">
                <button 
                    onClick={() => setIsAppStarted(false)}
                    className="self-start text-sm text-sky-600 hover:text-sky-800 flex items-center gap-1 font-medium"
                >
                    &larr; Back to Dashboard
                </button>
            </div>

          {/* Prompt and Editor Section */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 items-start">
            <div className="h-full">
                <PromptSection
                  taskType={taskType}
                  prompt={activeContext.prompt}
                  guidancePoints={activeContext.guidancePoints}
                  task1Guidance={activeContext.task1Guidance}
                  ideas={activeContext.brainstormingIdeas}
                  onNewPrompt={handleNewPrompt}
                  isLoadingPrompt={activeContext.isLoadingPrompt}
                  isLoadingIdeas={activeContext.isLoadingIdeas}
                  onGenerateIdeas={handleGenerateIdeas}
                  isCustomPromptMode={activeContext.isCustomPromptMode}
                  onSetCustomPromptMode={handleSetCustomPromptMode}
                  customPromptInput={activeContext.customPromptInput}
                  setCustomPromptInput={(val) => setActiveContext(p => ({...p, customPromptInput: val}))}
                  onGenerateFromCustomPrompt={handleGenerateFromCustomPrompt}
                  task1Image={activeContext.task1Image}
                  setTask1Image={(val) => setActiveContext(p => ({...p, task1Image: val}))}
                  apiKey={apiKey}
                />
            </div>
            <div className="h-full">
                <WritingEditor
                  taskType={taskType}
                  essay={activeContext.userEssay}
                  setEssay={(val) => setActiveContext(p => ({...p, userEssay: val}))}
                  onSubmit={handleSubmitEssay}
                  isLoading={activeContext.isLoadingFeedback}
                  onExportWord={handleExportToWord}
                  feedback={activeContext.feedback}
                />
            </div>
          </div>

          {/* Feedback Section */}
          <div className="w-full">
             <FeedbackDisplay 
                taskType={taskType} 
                feedback={activeContext.feedback} 
                isLoading={activeContext.isLoadingFeedback} 
            />
          </div>
        </div>
        {error && (
            <div className="fixed bottom-5 right-5 bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded-lg shadow-lg z-50" role="alert">
                <strong className="font-bold">Error: </strong>
                <span className="block sm:inline">{error}</span>
